import json
import logging
from google.cloud import storage, firestore, pubsub_v1
from google.cloud.exceptions import NotFound

def process_file_and_write_to_firestore(request):
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket' not in request_json or 'name' not in request_json:
        logging.error("Invalid request: missing bucket or name")
        return 'Invalid request', 400
    
    bucket_name = request_json['bucket']
    file_name = request_json['name']
    
    try:
        # Initialize clients
        storage_client = storage.Client()
        firestore_client = firestore.Client()
        pubsub_client = pubsub_v1.PublisherClient()
        
        # Get the file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            logging.error(f"File {file_name} not found in bucket {bucket_name}")
            return 'File not found', 404
        
        # Read file content
        content = blob.download_as_text()
        
        # Process content (example: count words)
        word_count = len(content.split())
        
        # Write to Firestore
        doc_ref = firestore_client.collection('processed_files').document(file_name)
        doc_ref.set({
            'filename': file_name,
            'bucket': bucket_name,
            'word_count': word_count,
            'processed_at': firestore.SERVER_TIMESTAMP
        })
        
        # Publish to Pub/Sub
        topic_path = pubsub_client.topic_path('your-project-id', 'file-processed-topic')
        message_data = {
            'filename': file_name,
            'bucket': bucket_name,
            'word_count': word_count
        }
        
        pubsub_client.publish(
            topic_path,
            json.dumps(message_data).encode('utf-8')
        )
        
        logging.info(f"Successfully processed {file_name}")
        return 'Success', 200
        
    except Exception as e:
        logging.error(f"Error processing file {file_name}: {str(e)}")
        return 'Error', 500